**A `debounce` function delays invoking a given function until after a specified wait time has elapsed since the last time it was called.**

```javascript
function debounce(func, wait) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), wait);
  };
}

// Example: Log input value only after 300ms of inactivity
const input = document.querySelector('input');
input.addEventListener('input', debounce((e) => {
  console.log('Debounced input:', e.target.value);
}, 300));
```
